CREATE OR REPLACE VIEW stock_mp_rango AS SELECT cod_material, cod_color, SUM(cant) AS cant, SUM(c1) AS c1, SUM(c2) AS c2, SUM(c3) AS c3, SUM(c4) AS c4, SUM(c5) AS c5, SUM(c6) AS c6, SUM(c7) AS c7, SUM(c8) AS c8, SUM(c9) AS c9, SUM(c10) AS c10 FROM (Scod_rango IS NOT NULL THEN (- Consumos_tarea.cant_4) ELSE 0 END) AS c4, SUM(CASE WHEN materiales.cod_rango IS NOT NULL THEN (- Consumos_tarea.cant_5) ELSE 0 END) AS c5, SUM(CASE WHEN materiales.cod_rango IS NOT NULL THEN (- Consumos_tarea.cant_6) ELSE 0 E;;
